// client/src/pages/OrderManagementPage.jsx
import React, { useState } from 'react';
import './AdminPage.css'; // Shared CSS for admin pages

const OrderManagementPage = () => {
    // Placeholder for orders data
    const [orders, setOrders] = useState([
        { id: 'ORD001', user: 'john.doe@example.com', total: 1500.00, status: 'Pending', date: '2025-05-30', items: [{ name: 'Gaming Laptop', qty: 1 }] },
        { id: 'ORD002', user: 'jane.smith@example.com', total: 240.00, status: 'Shipped', date: '2025-05-28', items: [{ name: 'Wireless Earbuds', qty: 2 }] },
        { id: 'ORD003', user: 'john.doe@example.com', total: 999.00, status: 'Delivered', date: '2025-05-25', items: [{ name: '4K Smart TV', qty: 1 }] },
    ]);

    const handleUpdateStatus = (orderId, newStatus) => {
        console.log(`Updating order ${orderId} to status: ${newStatus}`);
        // In a real app, you'd send a PUT request to update order status
        setOrders(orders.map(order =>
            order.id === orderId ? { ...order, status: newStatus } : order
        ));
    };

    const handleDeleteOrder = (orderId) => {
        console.log(`Deleting order ${orderId}`);
        // In a real app, you'd send a DELETE request
        setOrders(orders.filter(order => order.id !== orderId));
    };

    return (
        <div className="admin-page container">
            <h1>Order Management</h1>
            <div className="order-list-card card">
                {orders.length === 0 ? (
                    <p>No orders to display.</p>
                ) : (
                    <table className="order-table">
                        <thead>
                            <tr>
                                <th>Order ID</th>
                                <th>User Email</th>
                                <th>Total</th>
                                <th>Status</th>
                                <th>Date</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {orders.map(order => (
                                <tr key={order.id}>
                                    <td>{order.id}</td>
                                    <td>{order.user}</td>
                                    <td>${order.total.toFixed(2)}</td>
                                    <td>
                                        <select
                                            value={order.status}
                                            onChange={(e) => handleUpdateStatus(order.id, e.target.value)}
                                            className="status-select"
                                        >
                                            <option value="Pending">Pending</option>
                                            <option value="Processing">Processing</option>
                                            <option value="Shipped">Shipped</option>
                                            <option value="Delivered">Delivered</option>
                                            <option value="Cancelled">Cancelled</option>
                                        </select>
                                    </td>
                                    <td>{order.date}</td>
                                    <td>
                                        <button onClick={() => handleDeleteOrder(order.id)} className="btn btn-secondary delete-order-btn">Delete</button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                )}
            </div>
        </div>
    );
};

export default OrderManagementPage;
